javascript:(function(){if(window.__ytSubBM)return;window.__ytSubBM=true;const vid=new URLSearchParams(location.search).get('v');if(!vid){alert('YouTubeの動画ページで実行してください');window.__ytSubBM=false;return;}const ttl_=document.title.replace(/\s*-\s*YouTube\s*$/,'').trim();const F='-apple-system,BlinkMacSystemFont,"Hiragino Sans","Segoe UI",sans-serif',CD='rgba(255,255,255,0.55)',CE='#ff7a85',CS='#7ce895';const panel=document.createElement('div');panel.style.cssText='position:fixed;bottom:20px;right:20px;z-index:2147483647;background:rgba(20,22,32,0.55);backdrop-filter:blur(24px) saturate(180%);-webkit-backdrop-filter:blur(24px) saturate(180%);color:rgba(255,255,255,0.95);padding:10px 12px;border-radius:14px;border:1px solid rgba(255,255,255,0.14);font:13px/1.5 '+F+';width:230px;box-shadow:0 10px 40px rgba(0,0,0,0.45);letter-spacing:0.01em';const hdr=document.createElement('div');hdr.style.cssText='display:flex;justify-content:space-between;align-items:center;margin:0 -12px 8px;padding:0 12px 8px;border-bottom:1px solid rgba(255,255,255,0.08)';const ttl=document.createElement('b');ttl.textContent='言霊 / Kotodama';ttl.style.cssText='font-weight:600;letter-spacing:0.04em;font-size:13px';const cls=document.createElement('span');cls.textContent='×';cls.style.cssText='cursor:pointer;font-size:20px;line-height:1;color:rgba(255,255,255,0.5);transition:color 0.2s';cls.onmouseover=()=>cls.style.color='rgba(255,255,255,0.95)';cls.onmouseout=()=>cls.style.color='rgba(255,255,255,0.5)';cls.onclick=()=>{panel.remove();window.__ytSubBM=false;};hdr.appendChild(ttl);hdr.appendChild(cls);const st=document.createElement('div');st.style.cssText='margin-bottom:8px;color:'+CD+';font-size:12px;line-height:1.4';st.textContent='字幕をOFF→ONに切り替えてください';const btn=document.createElement('button');btn.textContent='Albireo用JSONをダウンロード';btn.style.cssText='visibility:hidden;width:100%;padding:8px;background:linear-gradient(135deg,rgba(124,58,237,0.95),rgba(236,72,153,0.95));color:#fff;border:none;border-radius:8px;cursor:pointer;font:600 13px/1 '+F+';letter-spacing:0.04em;transition:transform 0.15s,filter 0.15s';btn.onmouseover=()=>btn.style.filter='brightness(1.1)';btn.onmouseout=()=>btn.style.filter='brightness(1)';btn.onmousedown=()=>btn.style.transform='scale(0.97)';btn.onmouseup=()=>btn.style.transform='scale(1)';panel.appendChild(hdr);panel.appendChild(st);panel.appendChild(btn);document.body.appendChild(panel);let result=null,fetching=false;function setst(m,c){st.textContent=m;st.style.color=c||CD;}function parseEv(text){const evts=JSON.parse(text).events||[];return evts.filter(e=>e.segs).map(e=>({startMs:e.tStartMs,durationMs:e.dDurationMs,text:e.segs.map(s=>s.utf8).join('').trim()})).filter(e=>e.text);}const origOpen=XMLHttpRequest.prototype.open;XMLHttpRequest.prototype.open=function(m,url){if(typeof url==='string'&&url.includes('/timedtext?')){const p=new URLSearchParams(url.split('?')[1]);if(p.get('v')===vid&&!p.get('tlang'))fetchPair(url);}return origOpen.apply(this,arguments);};async function fetchPair(captured){if(fetching)return;fetching=true;const lang='ja';setst('字幕を取得中...');try{const[origText,transText]=await Promise.all([fetch(captured).then(r=>r.text()),fetch(captured+'&tlang='+lang).then(r=>r.text())]);if(origText.length<20){setst('元字幕データが空でした',CE);fetching=false;return;}if(transText.length<20){setst('翻訳データが空でした(多言語手動字幕の動画?)',CE);fetching=false;return;}const origs=parseEv(origText),trans=parseEv(transText);if(origs.length===0){setst('字幕のパースに失敗しました',CE);fetching=false;return;}const tm=new Map(trans.map(t=>[t.startMs,t.text]));const subs=origs.map(o=>({startMs:o.startMs,durationMs:o.durationMs,subtitle:o.text,translation:tm.get(o.startMs)||''}));result={id:vid,title:ttl_,subtitles:subs};setst('取得完了: '+subs.length+' 件',CS);btn.style.visibility='visible';}catch(e){setst('エラー: '+e.message,CE);fetching=false;}}btn.onclick=function(){if(!result)return;const blob=new Blob([JSON.stringify(result,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=vid+'_albireo.json';document.body.appendChild(a);a.click();document.body.removeChild(a);setTimeout(()=>URL.revokeObjectURL(url),1000);};})();
